import{_ as e,c as a,o as c,a as h}from"./app.ad17d727.js";const b=JSON.parse('{"title":"DB Schema","description":"","frontmatter":{},"headers":[{"level":2,"title":"什么是DB Schema","slug":"什么是db-schema","link":"#什么是db-schema","children":[]},{"level":2,"title":"如何编写DB Schema","slug":"如何编写db-schema","link":"#如何编写db-schema","children":[{"level":3,"title":"方式1、在web控制台编写schema","slug":"方式1、在web控制台编写schema","link":"#方式1、在web控制台编写schema","children":[]},{"level":3,"title":"方式2、在HBuilderX中编写schema（推荐）","slug":"方式2、在hbuilderx中编写schema-推荐","link":"#方式2、在hbuilderx中编写schema-推荐","children":[]},{"level":3,"title":"可视化管理schema文件插件","slug":"可视化管理schema文件插件","link":"#可视化管理schema文件插件","children":[]}]}],"relativePath":"3.框架/3.uniCloud/DBSchema.md","lastUpdated":1677576904000}'),l={name:"3.框架/3.uniCloud/DBSchema.md"},d=h('<h1 id="db-schema" tabindex="-1">DB Schema <a class="header-anchor" href="#db-schema" aria-hidden="true">#</a></h1><blockquote><blockquote><p><a href="https://uniapp.dcloud.net.cn/uniCloud/schema.html#db-schema%E6%A6%82%E8%BF%B0" target="_blank" rel="noreferrer">https://uniapp.dcloud.net.cn/uniCloud/schema.html#db-schema概述</a></p></blockquote></blockquote><h2 id="什么是db-schema" tabindex="-1">什么是DB Schema <a class="header-anchor" href="#什么是db-schema" aria-hidden="true">#</a></h2><p>unicloud定义数据表的一种方式，基于这种方式，可以快速定义一张表的字段，并配置权限、格式、校验等等</p><h2 id="如何编写db-schema" tabindex="-1">如何编写DB Schema <a class="header-anchor" href="#如何编写db-schema" aria-hidden="true">#</a></h2><h3 id="方式1、在web控制台编写schema" tabindex="-1">方式1、在web控制台编写schema <a class="header-anchor" href="#方式1、在web控制台编写schema" aria-hidden="true">#</a></h3><ol><li>登录 <a href="https://unicloud.dcloud.net.cn/" target="_blank" rel="noreferrer">uniCloud控制台</a>，选中一个数据表</li><li>点击表右侧页签 “表结构”，点击 “编辑” 按钮，在编辑区域编写 Schema，编写完毕后点保存按钮即可生效</li></ol><h3 id="方式2、在hbuilderx中编写schema-推荐" tabindex="-1">方式2、在HBuilderX中编写schema（推荐） <a class="header-anchor" href="#方式2、在hbuilderx中编写schema-推荐" aria-hidden="true">#</a></h3><p>创建schema</p><ol><li>在<code>uniCloud</code>项目右键，选择<code>创建database目录</code>（如已有目录则忽略）</li><li>在 database 目录右键选择<code>新建数据集合schema</code></li></ol><p>上传schema</p><ul><li>在单个schema文件右键可以只上传当前选中的schema。快捷键是【Ctrl+u】。（Ctrl+u是HBuilderX的通用快捷键，不管是发布App还是上传云函数、schema，都是Ctrl+u）</li><li>在database目录右键可以上传全部schema</li></ul><p>下载schema</p><ul><li>database目录右键可以下载所有schema及扩展校验函数</li></ul><p>HBuilderX中运行前端项目，在控制台选择连接本地云函数，或者本地云函数/云对象直接运行，此时本地编写的schema可直接生效，无需上传。方便编写调试</p><h3 id="可视化管理schema文件插件" tabindex="-1">可视化管理schema文件插件 <a class="header-anchor" href="#可视化管理schema文件插件" aria-hidden="true">#</a></h3><p>推荐使用HBuilderX插件进行可视化的开发schema文件</p><p><a href="https://ext.dcloud.net.cn/plugin?name=bctos-schema2view" target="_blank" rel="noreferrer">https://ext.dcloud.net.cn/plugin?name=bctos-schema2view</a></p><p>安装完在<code>*.schema.json</code>文件中右击，选择菜单第一项<code>可视化编辑</code></p>',19),s=[d];function t(i,r,n,o,m,u){return c(),a("div",null,s)}const _=e(l,[["render",t]]);export{b as __pageData,_ as default};
